import React, { useCallback, useMemo, useState } from 'react';
import {
  SearchInput,
  ParcelComponent,
  createParcelCreateFooterRenderer,
  isParcelRuntimeAvailable,
  type ParcelLinkConfig,
} from '@linm-soft-org/linm-web-common-components';
import type { CustomerDto } from '../../services/kt/models';
import df from '../../styles/documentForm.module.css';
import { formatAccountDisplay } from './accountSearchApi';
import {
  createCustomerSearchConfig,
  type CreateCustomerSearchConfigOptions,
  type CustomerSearchType,
} from './customerSearchConfig';
import {
  CUSTOMER_CREATE_PARCEL,
  type CustomerCreateParcelCustomProps,
} from './searchParcelConfig';

export interface CustomerSearchFieldProps {
  customerId: string;
  customerCode: string;
  customerName: string;
  onSelect: (customer: CustomerDto) => void;
  onClear: () => void;
  disabled?: boolean;
  placeholder?: string;
  className?: string;
  error?: string;
  /** Parcel link — default `CUSTOMER_CREATE_PARCEL`; `false` = no create footer */
  createParcel?: ParcelLinkConfig | false;
  searchConfigOptions?: CreateCustomerSearchConfigOptions;
  defaultCustomerType?: CustomerSearchType | 'Both';
  testIdPrefix?: string;
  /** Một ô `mã — tên`. Mặc định: false — 2 ô mã + tên cùng hàng. */
  singleField?: boolean;
}

/**
 * SearchControl consumer — SearchInput + ParcelComponent (`search-parcel.md`).
 */
export const CustomerSearchField: React.FC<CustomerSearchFieldProps> = ({
  customerId,
  customerCode,
  customerName,
  onSelect,
  onClear,
  disabled = false,
  placeholder,
  className,
  error,
  createParcel = CUSTOMER_CREATE_PARCEL,
  searchConfigOptions,
  defaultCustomerType = 'Customer',
  testIdPrefix = 'customer-search',
  singleField = false,
}) => {
  const tid = (suffix: string) => `${testIdPrefix}-${suffix}`;
  const searchConfig = useMemo(
    () => createCustomerSearchConfig(searchConfigOptions ?? {}),
    [searchConfigOptions],
  );

  const [parcelOpen, setParcelOpen] = useState(false);
  const [initialName, setInitialName] = useState('');

  const parcelLink = createParcel === false ? null : (createParcel ?? CUSTOMER_CREATE_PARCEL);
  const canCreate = !!parcelLink && !disabled && isParcelRuntimeAvailable();

  const parcelCustomProps = useMemo((): CustomerCreateParcelCustomProps => ({
    initialName,
    defaultCustomerType,
    onSuccess: created => {
      onSelect({
        customerId: created.customerId,
        code: created.code,
        name: created.name,
        phone: created.phone,
        customerType: defaultCustomerType,
        isActive: true,
      });
      setParcelOpen(false);
    },
    onCancel: () => setParcelOpen(false),
  }), [initialName, defaultCustomerType, onSelect]);

  const renderCreateFooter = useMemo(() => {
    if (!canCreate || !parcelLink) return undefined;
    return createParcelCreateFooterRenderer({
      link: parcelLink,
      testId: tid('create-btn'),
      defaultLabel: 'Tạo mới khách hàng',
      onOpen: term => {
        setInitialName(term);
        setParcelOpen(true);
      },
    });
  }, [canCreate, parcelLink, testIdPrefix]);

  const handleParcelClose = useCallback(() => setParcelOpen(false), []);

  const rootClassName = [
    className,
    !singleField ? df.customerLookupDualRow : undefined,
  ]
    .filter(Boolean)
    .join(' ');

  return (
    <>
      <SearchInput
        config={searchConfig}
        className={rootClassName || undefined}
        value={customerId}
        primaryDisplay={
          singleField
            ? formatAccountDisplay(customerCode, customerName)
            : customerCode
        }
        secondaryDisplay={singleField ? '' : customerName}
        onChange={onSelect}
        onClear={onClear}
        showLabel={false}
        showSecondaryInput={!singleField}
        placeholder={placeholder}
        disabled={disabled}
        error={error}
        renderDropdownFooter={renderCreateFooter}
      />

      {parcelLink && (
        <ParcelComponent
          isOpen={parcelOpen}
          link={parcelLink}
          customProps={parcelCustomProps}
          onClose={handleParcelClose}
          testIdPrefix={tid('parcel')}
        />
      )}
    </>
  );
};
