import type { SelectOption } from '@linm-soft-org/linm-web-common-components';

export const DEPARTMENT_FIELD_LABEL = 'Đơn vị';

export const DEPARTMENT_PLACEHOLDER_OPTION: SelectOption = {
  value: '',
  label: '— Chọn đơn vị —',
};

export interface DepartmentLookupItem {
  id: string;
  code: string;
  name: string;
  label: string;
}

/** Parse init-data `{ value: id, label: "CODE — Name" }`. */
export function parseDepartmentOptions(options: SelectOption[]): DepartmentLookupItem[] {
  return options.map(o => {
    const sep = ' — ';
    const i = o.label.indexOf(sep);
    const code = i >= 0 ? o.label.slice(0, i).trim() : String(o.value);
    const name = i >= 0 ? o.label.slice(i + sep.length).trim() : o.label;
    return { id: String(o.value), code, name, label: o.label };
  });
}

export function resolveDepartmentName(code: string, options: SelectOption[]): string {
  if (!code) return '';
  return parseDepartmentOptions(options).find(d => d.code === code)?.name ?? '';
}

export function resolveDepartmentById(id: string, options: SelectOption[]): DepartmentLookupItem | undefined {
  if (!id) return undefined;
  return parseDepartmentOptions(options).find(d => d.id === id);
}

export function withDepartmentPlaceholder(
  options: SelectOption[],
): SelectOption[] {
  return [DEPARTMENT_PLACEHOLDER_OPTION, ...options];
}

/** @deprecated Line field dùng SearchInput static — giữ cho Select header nếu cần */
export function departmentOptionsAsCodeSelect(options: SelectOption[]): SelectOption[] {
  return options.map(o => {
    const sep = ' — ';
    const i = o.label.indexOf(sep);
    const code = i >= 0 ? o.label.slice(0, i).trim() : o.value;
    return { value: code, label: o.label };
  });
}

/** @deprecated Line field dùng SearchInput static */
export function withDepartmentCodePlaceholder(options: SelectOption[]): SelectOption[] {
  return [{ value: '', label: '— Chọn mã đơn vị —' }, ...options];
}
